# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import json
from flask import Flask, request
from web3 import Web3

app = Flask(__name__)


@app.route('/authenticate', methods=['POST'])
def authenticate():
    # Get the data from the request body
    data = request.get_json()

    # Decode the message and signature
    message = json.loads(data['message'])
    signature = Web3.toBytes(hexstr=data['signature'])

    # Recover the address using ECDSA recover method
    recoveredAddress = Web3.eth.account.recoverHash(
        message,
        signature
    )

    # Return the recovered address as a response to the user
    return json.dumps({ 'address': recoveredAddress })


if __name__ == '__main__':
    app.run()